GameListener = {}

local function showEngineWindow(name)
    local window = GUIManager:getWindowByName(name)
    if not window then
        return
    end
    window:SetVisible(true)
end

function GameListener:init()
    BaseListener.registerCallBack(GameReadyEvent, self.onGameReady)
end

function GameListener.onGameReady()
    showEngineWindow("Main-Gun-Operate-ThrowBtn")
end

return GameListener